import { Link } from 'react-router-dom';
import { useEffect, useState } from 'react';
import './HomePage.css';

const HomePage = () => {
  const [showLocationPrompt, setShowLocationPrompt] = useState(true);

  useEffect(() => {
    const hasSeenPrompt = localStorage.getItem('locationPromptSeen');
    if (hasSeenPrompt) {
      setShowLocationPrompt(false);
    }
  }, []);

  const handleLocationPermission = () => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          console.log("Location access granted");
          localStorage.setItem('locationPromptSeen', 'true');
          setShowLocationPrompt(false);
        },
        (error) => {
          console.error("Error getting location:", error);
        }
      );
    }
  };

  return (
    <div className="home-page">
      {showLocationPrompt && (
        <div className="location-prompt">
          <div className="prompt-content">
            <h3>Enable Location Services</h3>
            <p>Allow Manchitra to access your location for better experience</p>
            <button onClick={handleLocationPermission}>Enable Location</button>
          </div>
        </div>
      )}

      <div className="hero-section">
        <div className="hero-overlay">
          <div className="hero-content">
            <h1>Discover Durga Puja Mandaps</h1>
            <p>Navigate through the festive celebrations with ease</p>
            <div className="cta-buttons">
              <Link to="/mandaps" className="cta-button primary">
                Find Mandaps Near You
              </Link>
              <Link to="/services" className="cta-button secondary">
                Explore Nearby Services
              </Link>
              <h2 class="section-title">Features</h2>
        <div class="feature-grid">
            <div class="feature-card">
                <div class="feature-icon">🗺</div>
                <h3>Durga Puja Mandap Detection</h3>
                <p>Find and explore nearby Durga Puja mandaps with details on themes, crowd density, and timings.</p>
            </div>
            <div class="feature-card">
                <div class="feature-icon">🍽</div>
                <h3>Nearby Services</h3>
                <p>Discover restaurants, petrol pumps, transport options, and emergency services around you.</p>
            </div>
            <div class="feature-card">
                <div class="feature-icon">🔍</div>
                <h3>Smart Search & Filters</h3>
                <p>Easily search for specific mandaps, restaurants, or services with advanced filters.</p>
            </div>
            <div class="feature-card">
                <div class="feature-icon">📍</div>
                <h3>Real-Time Navigation</h3>
                <p>Get directions to your desired location with optimized routes and live updates.</p>
            </div>
            <div class="feature-card">
                <div class="feature-icon">🌍</div>
                <h3>Community Contributions</h3>
                <p>Users can add new mandaps, rate locations, and share reviews for a better experience.</p>
            </div>
        </div>
            </div>
          </div>
        </div>
      </div>
    </div>
    
  );
};

export default HomePage;
